<?php require 'auth.php'; $err=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $email=$_POST['email']??''; $pass=$_POST['password']??''; foreach(users()['users'] as $u){ if($u['email']===$email && password_verify($pass,$u['password_hash'])){ $_SESSION['admin']=$email; header('Location: index.php'); exit; } } $err='Invalid login'; } ?>
